private static IResult HandleRequest(HttpContext context, IMemoryCache memoryCache, LiquidViewParser liquidViewParser, IOptions<TemplateOptions> templateOptions)
    {
        // We could check that the current cache entry matches the requested hash, but instead we always return the actual content that
        // the client should have. The hash is only used for cache busting on the client.

        // The cache entry will be busted whenever the filters or tags change, i.e. when some features are enabled or disabled.

        var scriptBytes = memoryCache.GetOrCreate("LiquidIntellisenseScript", entry =>
        {
            entry.SetSlidingExpiration(TimeSpan.FromHours(1));

            return GenerateScriptBytes(liquidViewParser, templateOptions);
        });

        if (scriptBytes == null)
        {
            return Results.StatusCode(500);
        }

        // Set the cache timeout to the maximum allowed length of one year
        // max-age is needed because immutable is not widely supported
        context.Response.Headers.CacheControl = "public, max-age=31536000, immutable";

        return Results.Bytes(scriptBytes, MediaTypeNames.Text.JavaScript);
    }

private static async Task<IResult> HandleAsync(
        ReadNotificationViewModel model,
        IAuthorizationService authorizationService,
        IHttpContextAccessor httpContextAccessor,
        ITagCache tagCache,
        YesSql.ISession session,
        IClock clock)
    {
        if (string.IsNullOrEmpty(model?.MessageId))
        {
            return TypedResults.BadRequest();
        }

        if (!await authorizationService.AuthorizeAsync(httpContextAccessor.HttpContext.User, NotificationPermissions.ManageNotifications))
        {
            return TypedResults.Forbid();
        }

        var userId = httpContextAccessor.HttpContext.User.FindFirstValue(ClaimTypes.NameIdentifier);

        var notification = await session.Query<Notification, NotificationIndex>(x => x.NotificationId == model.MessageId && x.UserId == userId, collection: NotificationConstants.NotificationCollection).FirstOrDefaultAsync();

        if (notification == null)
        {
            return TypedResults.NotFound();
        }

        var updated = false;
        var readInfo = notification.GetOrCreate<NotificationReadInfo>();

        if (!readInfo.IsRead)
        {
            readInfo.ReadAtUtc = clock.UtcNow;
            readInfo.IsRead = true;
            notification.Put(readInfo);

            updated = true;

            await session.SaveAsync(notification, collection: NotificationConstants.NotificationCollection);
            await tagCache.RemoveTagAsync(NotificationsHelper.GetUnreadUserNotificationTagKey(httpContextAccessor.HttpContext.User.Identity.Name));
        }

        return TypedResults.Ok(new
        {
            messageId = model.MessageId,
            updated,
        });
    }

private static async Task<IResult> HandleAsync(
        IAuthorizationService authorizationService,
        HttpContext httpContext,
        IRewriteRulesManager rewriteRulesManager,
        ResortingRequest model)
    {

        if (!model.OldIndex.HasValue || !model.NewIndex.HasValue)
        {
            return TypedResults.BadRequest();
        }

        if (!await authorizationService.AuthorizeAsync(httpContext.User, UrlRewritingPermissions.ManageUrlRewritingRules))
        {
            return TypedResults.Forbid();
        }

        await rewriteRulesManager.ResortOrderAsync(model.OldIndex.Value, model.NewIndex.Value);

        return TypedResults.Ok();
    }
